// Polling interval for supercomputer execution status (ms). Change this value to adjust frequency.
const SUPERCOMPUTER_STATUS_POLL_MS = 5000; // 5 seconds

/**
 * AzureLoadingManager - Manages loading states for Azure settings dropdowns
 * Provides visual feedback during authentication and data loading operations
 */
class AzureLoadingManager {
    constructor() {
        this.states = new Map();
        this.overlay = null;
        this.currentOperation = null;
        this.abortController = null;
    }

    /**
     * Initialize the loading overlay element
     */
    initOverlay() {
        if (this.overlay) return;

        this.overlay = document.createElement('div');
        this.overlay.id = 'azure-loading-overlay';
        this.overlay.className = 'azure-loading-overlay hidden';
        this.overlay.innerHTML = `
            <div class="azure-loading-content">
                <div class="azure-loading-spinner"></div>
                <div class="azure-loading-message">Loading...</div>
                <div class="azure-loading-detail"></div>
                <button class="azure-loading-cancel hidden">Cancel</button>
            </div>
        `;

        // Add cancel handler
        const cancelBtn = this.overlay.querySelector('.azure-loading-cancel');
        cancelBtn.addEventListener('click', () => this.cancelOperation());

        document.body.appendChild(this.overlay);
    }

    /**
     * Set loading state for a dropdown
     */
    setLoading(dropdownId, message = 'Loading...') {
        this.states.set(dropdownId, { state: 'loading', message });
        this.updateDropdownUI(dropdownId, 'loading');
        console.log(`🔄 [${dropdownId}] Loading: ${message}`);
    }

    /**
     * Set authenticating state - shows overlay with message
     */
    setAuthenticating(message = 'Authenticating with Azure...', detail = '') {
        this.initOverlay();

        const messageEl = this.overlay.querySelector('.azure-loading-message');
        const detailEl = this.overlay.querySelector('.azure-loading-detail');
        const cancelBtn = this.overlay.querySelector('.azure-loading-cancel');

        messageEl.textContent = message;
        detailEl.textContent = detail || 'A browser window may open for authentication...';
        cancelBtn.classList.remove('hidden');

        this.overlay.classList.remove('hidden');
        console.log(`🔐 Authenticating: ${message}`);
    }

    /**
     * Set success state for a dropdown
     */
    setSuccess(dropdownId, itemCount = null) {
        this.states.set(dropdownId, { state: 'success' });
        this.updateDropdownUI(dropdownId, 'success');
        this.hideOverlay();

        const countMsg = itemCount !== null ? ` (${itemCount} items)` : '';
        console.log(`✅ [${dropdownId}] Success${countMsg}`);

        // Remove success state after animation
        setTimeout(() => {
            this.updateDropdownUI(dropdownId, 'idle');
        }, 500);
    }

    /**
     * Set error state for a dropdown with optional retry
     */
    setError(dropdownId, error, retryFn = null) {
        this.states.set(dropdownId, { state: 'error', error, retryFn });
        this.updateDropdownUI(dropdownId, 'error', error, retryFn);
        this.hideOverlay();
        console.error(`❌ [${dropdownId}] Error: ${error}`);
    }

    /**
     * Clear all states and hide overlay
     */
    clearAll() {
        this.states.clear();
        this.hideOverlay();

        // Clear all dropdown states
        ['tenant-id', 'subscription-id', 'resource-group', 'location'].forEach(id => {
            this.updateDropdownUI(id, 'idle');
        });
    }

    /**
     * Hide the loading overlay
     */
    hideOverlay() {
        if (this.overlay) {
            this.overlay.classList.add('hidden');
        }
    }

    /**
     * Cancel the current operation
     */
    cancelOperation() {
        if (this.abortController) {
            this.abortController.abort();
            this.abortController = null;
        }
        this.hideOverlay();
        console.log('⚠️ Operation cancelled by user');
    }

    /**
     * Create an AbortController for cancellable operations
     */
    createAbortController(timeoutMs = 60000) {
        this.abortController = new AbortController();

        // Auto-abort after timeout
        setTimeout(() => {
            if (this.abortController) {
                this.abortController.abort();
            }
        }, timeoutMs);

        return this.abortController;
    }

    /**
     * Update dropdown UI based on state
     */
    updateDropdownUI(dropdownId, state, error = null, retryFn = null) {
        const select = document.getElementById(dropdownId);
        if (!select) return;

        // Find the setting-group container
        const settingGroup = select.closest('.setting-group');
        if (!settingGroup) return;

        // Remove all state classes
        settingGroup.classList.remove('loading', 'success', 'error');

        // Remove existing error message
        const existingError = settingGroup.querySelector('.azure-dropdown-error');
        if (existingError) {
            existingError.remove();
        }

        // Apply new state
        switch (state) {
            case 'loading':
                settingGroup.classList.add('loading');
                break;

            case 'success':
                settingGroup.classList.add('success');
                break;

            case 'error':
                settingGroup.classList.add('error');
                if (error) {
                    this.showErrorMessage(settingGroup, error, retryFn);
                }
                break;

            case 'idle':
            default:
                // Clean state, nothing to add
                break;
        }
    }

    /**
     * Show error message with retry button
     */
    showErrorMessage(container, error, retryFn) {
        const errorDiv = document.createElement('div');
        errorDiv.className = 'azure-dropdown-error';
        errorDiv.innerHTML = `
            <span class="error-icon">⚠️</span>
            <span class="error-message">${this.escapeHtml(error)}</span>
            ${retryFn ? '<button class="azure-retry-btn">Retry</button>' : ''}
        `;

        if (retryFn) {
            const retryBtn = errorDiv.querySelector('.azure-retry-btn');
            retryBtn.addEventListener('click', async () => {
                errorDiv.remove();
                await retryFn();
            });
        }

        container.appendChild(errorDiv);
    }

    /**
     * Get user-friendly error message from technical error
     */
    getUserFriendlyError(error) {
        const message = error?.message || String(error);

        // Map technical errors to user-friendly messages
        const errorPatterns = [
            { pattern: /AbortError/i, message: 'Request timed out. Please try again.' },
            { pattern: /NetworkError|Failed to fetch/i, message: 'Network error. Check your connection.' },
            { pattern: /401|Unauthorized/i, message: 'Authentication required. Please sign in.' },
            { pattern: /403|Forbidden/i, message: 'Access denied. Check your permissions.' },
            { pattern: /404|Not found/i, message: 'Resource not found.' },
            { pattern: /5\d{2}/i, message: 'Azure service error. Please try again later.' },
            { pattern: /AADSTS/i, message: 'Azure AD error. Try signing out and back in.' },
            { pattern: /timeout/i, message: 'Request timed out. Please try again.' }
        ];

        for (const { pattern, message: friendlyMessage } of errorPatterns) {
            if (pattern.test(message)) {
                return friendlyMessage;
            }
        }

        // Return original if no pattern matches, but truncate if too long
        return message.length > 100 ? message.substring(0, 100) + '...' : message;
    }

    /**
     * Escape HTML to prevent XSS
     */
    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
}

