    initializeDiscoveryClient() {
        // Initialize the Discovery publishing client
        if (typeof DiscoveryPublishingClient !== 'undefined') {
            this.discoveryClient = new DiscoveryPublishingClient(this);
            // Expose globally for inline onclick handlers
            window.discoveryClient = this.discoveryClient;
            console.log('Discovery Client initialized');
            // Load Azure configuration if available
            this.discoveryClient.loadAzureConfigFromServer().then(() => {
                console.log('Azure config loaded for Discovery Client:', this.discoveryClient.azureConfig);
            }).catch(err => {
                console.warn('Could not load Azure config for Discovery Client:', err);
            });
        } else {
            console.warn('DiscoveryPublishingClient not available');
        }
    }

    showDiscoveryPublishDialog() {
        if (this.discoveryClient) {
            this.discoveryClient.showDiscoveryDialog();
        } else {
            showAppAlert({ title: 'Unavailable', message: 'Discovery publishing functionality is not available' });
        }
    }

