    /**
     * Write content to a file in the output directory
     * @param {string} filename - Name of the file to create
     * @param {string} content - Content to write to the file
     * @param {boolean} overwrite - Whether to overwrite if file exists (default: true)
     * @returns {Promise<Object>} - Response object with success status
     */
    async writeFile(filename, content, overwrite = true) {
        try {
            const response = await fetch('/api/write-file', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    filename: filename,
                    content: content,
                    overwrite: overwrite
                })
            });
            
            const data = await response.json();
            
            if (!response.ok) {
                throw new Error(data.error || 'Failed to write file');
            }
            
            console.log(`✅ File written successfully: ${filename} (${data.size} bytes)`);
            
            // Refresh the results list to show the new file
            await this.loadResults();
            
            return data;
        } catch (error) {
            console.error(`❌ Error writing file ${filename}:`, error);
            throw error;
        }
    }
    
