    /** Handle cloning the current Workflow Agent (backend copies files & catalog record). */
    async handleCloneWorkflowAgent() {
        const source = this.getCurrentAgentName();
        if (!source) {
            alert('No Workflow Agent selected.');
            return;
        }
        const isEntry = (this.availableAgents.workflow_agents || []).some(ea => ea.name === source);
        if (!isEntry) {
            alert('Current agent is not an Workflow Agent.');
            return;
        }
        const newName = prompt('Enter new unique name for cloned Workflow Agent:', source + 'Copy');
        if (!newName) return;
        if (newName.trim() === source) {
            alert('New name must be different from source name.');
            return;
        }
        try {
            const resp = await fetch('/api/workflow-agents/clone', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ source_name: source, new_name: newName.trim() })
            });
            if (!resp.ok) {
                const text = await resp.text();
                throw new Error(text || 'Clone failed');
            }
            const result = await resp.json();
            if (!result.success) {
                throw new Error(result.error || 'Clone failed');
            }
            // Refresh agent list and select the clone
            await this.loadAvailableAgents();
            this.renderAgentDropdown();
            const cloned = (this.availableAgents.workflow_agents || []).find(ea => ea.name === newName.trim());
            if (cloned) {
                await this.selectAgent(cloned);
                this.handleAgentModeSwitch(cloned);
            }
            this.showToast?.(`Workflow Agent cloned: ${source} -> ${newName}`, 'success');
        } catch (e) {
            console.error('Clone Workflow Agent error:', e);
            alert('Failed to clone Workflow Agent: ' + (e.message || e));
        }
    }

    /** Handle deleting the current KB Agent (removes catalog entry only). */
    async handleDeleteKbAgent() {
        const name = this.getCurrentAgentName();
        if (!name) {
            alert('No KB Agent selected.');
            return;
        }
        // Verify this is a KB agent
        const isKb = (this.availableAgents.kb_agents || []).some(ka => ka.name === name);
        if (!isKb) {
            alert('Current agent is not a KB Agent.');
            return;
        }
        if (!confirm(`Delete KB Agent "${name}"?\nThis will remove its catalog record and delete the YAML file. This cannot be undone.`)) {
            return;
        }
        try {
            const resp = await fetch(`/api/agents/catalog/delete/${encodeURIComponent(name)}`, { method: 'DELETE' });
            if (!resp.ok) {
                const text = await resp.text();
                throw new Error(text || 'Delete failed');
            }
            const result = await resp.json();
            if (!result.success) {
                throw new Error(result.error || 'Delete failed');
            }
            this.showToast?.(`KB Agent "${name}" deleted successfully`, 'success');
            // Reload agents and adjust selection
            await this.loadAvailableAgents();
            this.renderAgentDropdown();
            // Prefer selecting another KB agent if any remain, else fallback to other types
            let next = null;
            if (this.availableAgents.kb_agents && this.availableAgents.kb_agents.length) {
                next = this.availableAgents.kb_agents[0];
            } else if (this.availableAgents.workflow_agents && this.availableAgents.workflow_agents.length) {
                next = this.availableAgents.workflow_agents[0];
            } else if (this.availableAgents.tool_agents && this.availableAgents.tool_agents.length) {
                next = this.availableAgents.tool_agents[0];
            }
            if (next) {
                await this.selectAgent(next);
                this.handleAgentModeSwitch(next);
            } else {
                // No agents at all; fallback to clearing KB mode
                this.switchToRegularMode();
            }
        } catch (e) {
            console.error('Delete KB Agent error:', e);
            alert('Failed to delete KB Agent: ' + (e.message || e));
        }
    }

