// Reusable helper to flash a green check on a button for 1s without changing layout
window.flashButtonSuccess = function(button){
    if(!button) return;
    const originalText = button.__origText || button.textContent;
    if(!button.__origText) button.__origText = originalText;
    button.classList.add('flash-success');
    // Temporarily replace text with original text (ensures consistent) so :after check appears clean
    // No text change needed; style adds check. If we wanted icon swap, could modify innerHTML here.
    clearTimeout(button.__flashTimer);
    button.__flashTimer = setTimeout(()=>{
        button.classList.remove('flash-success');
    }, 1000);
};

// Shows a tri-option dialog (primary / secondary / cancel). Returns a Promise<'primary'|'secondary'|'cancel'>.
function showAppTriDialog({ title = 'Confirm', message = '', primaryLabel = 'OK', secondaryLabel = 'Alt', cancelLabel = 'Cancel' } = {}) {
    return new Promise((resolve) => {
        const overlay = document.getElementById('appDialog');
        const titleEl = document.getElementById('appDialogTitle');
        const msgEl = document.getElementById('appDialogMessage');
        const okBtn = document.getElementById('appDialogOk');
        const cancelBtn = document.getElementById('appDialogCancel');
        const altBtn = document.getElementById('appDialogAlt');
        const closeBtn = document.getElementById('appDialogClose');

        if (!overlay || !titleEl || !msgEl || !okBtn || !cancelBtn || !closeBtn || !altBtn) {
            // Fallback emulate with confirm + prompt chain (limited)
            const conf = confirm(message || title);
            resolve(conf ? 'primary' : 'cancel');
            return;
        }

        titleEl.textContent = title || 'Confirm';
        msgEl.innerText = message || '';
        okBtn.textContent = primaryLabel || 'OK';
        altBtn.textContent = secondaryLabel || 'Secondary';
        cancelBtn.textContent = cancelLabel || 'Cancel';

        // Ensure all three visible
        cancelBtn.style.display = '';
        okBtn.style.display = '';
        altBtn.classList.remove('hidden');
        altBtn.style.display = '';

        const cleanup = () => {
            okBtn.onclick = null;
            cancelBtn.onclick = null;
            altBtn.onclick = null;
            closeBtn.onclick = null;
            document.removeEventListener('keydown', onKeyDown);
            overlay.classList.add('hidden');
        };

        const onKeyDown = (e) => {
            if (e.key === 'Escape') {
                cleanup();
                resolve('cancel');
            }
        };

        okBtn.onclick = () => { cleanup(); resolve('primary'); };
        altBtn.onclick = () => { cleanup(); resolve('secondary'); };
        cancelBtn.onclick = () => { cleanup(); resolve('cancel'); };
        closeBtn.onclick = () => { cleanup(); resolve('cancel'); };
        document.addEventListener('keydown', onKeyDown);

    overlay.classList.remove('hidden');
    // Default focus Cancel (rightmost)
    setTimeout(() => { try { cancelBtn.focus(); } catch(_) {} }, 0);
    });
}

// Shows an alert-style dialog with a single OK button. Returns a Promise<void>.
function showAppAlert({ title = 'Notice', message = '', okLabel = 'OK' } = {}) {
    return new Promise((resolve) => {
        const overlay = document.getElementById('appDialog');
        const titleEl = document.getElementById('appDialogTitle');
        const msgEl = document.getElementById('appDialogMessage');
        const okBtn = document.getElementById('appDialogOk');
        const cancelBtn = document.getElementById('appDialogCancel');
        const closeBtn = document.getElementById('appDialogClose');

        if (!overlay || !titleEl || !msgEl || !okBtn || !cancelBtn || !closeBtn) {
            // Fallback to native alert
            alert(message || title);
            resolve();
            return;
        }

        // Set content
        titleEl.textContent = title || 'Notice';
        msgEl.innerText = message || '';
        okBtn.textContent = okLabel || 'OK';

        // Hide cancel for alert variant
        cancelBtn.style.display = 'none';
        okBtn.style.display = '';

        // Clean up previous handlers
        const cleanup = () => {
            okBtn.onclick = null;
            closeBtn.onclick = null;
            document.removeEventListener('keydown', onKeyDown);
            // Restore cancel visibility for next time
            cancelBtn.style.display = '';
            overlay.classList.add('hidden');
        };

        const onKeyDown = (e) => {
            if (e.key === 'Escape' || e.key === 'Enter') {
                cleanup();
                resolve();
            }
        };

        okBtn.onclick = () => { cleanup(); resolve(); };
        closeBtn.onclick = () => { cleanup(); resolve(); };
        document.addEventListener('keydown', onKeyDown);

        // Show dialog
    overlay.classList.remove('hidden');
    setTimeout(() => { try { okBtn.focus(); } catch(_) {} }, 0);
    });
}

// Knowledge Base Agent Creator Class
class KnowledgeBaseCreator {
    constructor(discoveryAgent) {
        this.discoveryAgent = discoveryAgent;
        this.currentStep = 1;
        this.agentData = {};
        this.generatedDefinition = '';
        
        this.createModal();
        this.bindEvents();
    }
    
    createModal() {
        // Create modal HTML
        const modalHtml = `
            <div id="createKnowledgeBaseModal" class="modal-overlay" style="display: none;">
                <div class="modal-content knowledge-base-modal" style="width: 90%; max-width: 800px;">
                    <div class="modal-header">
                        <h3 id="kbModalTitle">Create Knowledge Base Agent</h3>
                        <button class="modal-close" id="kbModalCloseBtn">×</button>
                    </div>
                    <div class="modal-body" style="padding: 20px;">
                        <!-- Step 1: Configuration -->
                        <div id="kbStep1" class="step-content active">
                            <div class="form-group" style="margin-bottom: 20px;">
                                <label for="kbAgentName" style="display: block; margin-bottom: 8px; font-weight: 500;">Agent Name:</label>
                                <input type="text" id="kbAgentName" value="KnowledgeBaseAgent" 
                                       placeholder="Enter agent name (3-24 chars, letters/digits/dashes, start and end with letter)"
                                       style="width: 100%; padding: 10px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px;">
                                <div id="kbAgentNameValidation" class="validation-message" style="margin-top: 5px; font-size: 12px; display: none;"></div>
                                <small style="color: #666; font-size: 12px; margin-top: 4px; display: block;">The name for your knowledge base agent</small>
                            </div>
                            
                            <div class="form-group" style="margin-bottom: 20px;">
                                <label for="kbDomains" style="display: block; margin-bottom: 8px; font-weight: 500;">Domain(s):</label>
                                <textarea id="kbDomains" rows="4" 
                                          placeholder="Describe the domains this knowledge base agent should cover (e.g., chemistry, materials science, drug discovery, etc.)"
                                          style="width: 100%; padding: 10px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px; resize: vertical; font-family: inherit;"></textarea>
                                <small style="color: #666; font-size: 12px; margin-top: 4px; display: block;">Free text description of the knowledge domains this agent will specialize in</small>
                            </div>
                            <!-- Modal-scoped knowledge base list (used by modal loadKnowledgeBases). This keeps the modal self-contained and avoids id conflicts with the right-panel KB mode -->
                            <div id="kbModalKnowledgeBaseList" class="knowledge-base-list" style="display: none; padding: 0 15px;">
                                <!-- Filled dynamically when modal opens -->
                            </div>
                        </div>
                        
                        <!-- Step 2: Preview -->
                        <div id="kbStep2" class="step-content" style="display: none;">
                            <div class="preview-section" style="width: 100%;">
                                <div class="preview-header" style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 15px;">
                                    <h4 style="margin: 0;">Generated Agent Definition</h4>
                                    <button id="kbRegenerateBtn" class="btn-secondary">
                                        <span class="button-text">Regenerate</span>
                                    </button>
                                </div>
                                <textarea id="kbAgentDefinition" rows="20" 
                                          style="width: 100%; padding: 12px; font-family: 'Courier New', monospace; font-size: 12px; border: 1px solid #ddd; border-radius: 4px; resize: vertical; box-sizing: border-box;"></textarea>
                            </div>
                        </div>
                    </div>
                    <div class="modal-footer" style="padding: 15px 20px; border-top: 1px solid #eee; display: flex; justify-content: space-between; align-items: center;">
                        <div class="step-progress">
                            <span class="step-indicator active" data-step="1" style="display: inline-block; width: 24px; height: 24px; border-radius: 50%; background: #0078d4; color: white; text-align: center; line-height: 24px; font-size: 12px; font-weight: 600;">1</span>
                            <span class="step-connector" style="display: inline-block; width: 20px; height: 2px; background: #e5e5e5; margin: 0 8px; vertical-align: middle;"></span>
                            <span class="step-indicator" data-step="2" style="display: inline-block; width: 24px; height: 24px; border-radius: 50%; background: #e5e5e5; color: #666; text-align: center; line-height: 24px; font-size: 12px; font-weight: 600;">2</span>
                        </div>
                        <div class="modal-actions" style="display: flex; gap: 10px;">
                            <button id="kbModalCancelBtn" class="btn-secondary">Cancel</button>
                            <button id="kbModalBackBtn" class="btn-secondary" style="display: none;">Back</button>
                            <button id="kbModalNextBtn" class="btn-primary">Next</button>
                            <button id="kbModalCreateBtn" class="btn-primary" style="display: none;">Create Agent</button>
                        </div>
                    </div>
                </div>
            </div>
        `;
        
        // Append to body
        document.body.insertAdjacentHTML('beforeend', modalHtml);
        
        // Get references
        this.modal = document.getElementById('createKnowledgeBaseModal');
        this.modalTitle = document.getElementById('kbModalTitle');
        this.modalCloseBtn = document.getElementById('kbModalCloseBtn');
        this.modalCancelBtn = document.getElementById('kbModalCancelBtn');
        this.modalBackBtn = document.getElementById('kbModalBackBtn');
        this.modalNextBtn = document.getElementById('kbModalNextBtn');
        this.modalCreateBtn = document.getElementById('kbModalCreateBtn');
        
        // Form elements
        this.agentNameInput = document.getElementById('kbAgentName');
        this.domainsInput = document.getElementById('kbDomains');
        this.agentDefinitionTextarea = document.getElementById('kbAgentDefinition');
        this.regenerateBtn = document.getElementById('kbRegenerateBtn');
        
        // Step elements
        this.step1 = document.getElementById('kbStep1');
        this.step2 = document.getElementById('kbStep2');
        this.footerStepIndicators = this.modal.querySelectorAll('.step-progress .step-indicator');
    }
    
    bindEvents() {
        // Modal control events
        this.modalCloseBtn?.addEventListener('click', () => this.hide());
        this.modalCancelBtn?.addEventListener('click', () => this.hide());
        this.modalBackBtn?.addEventListener('click', () => this.previousStep());
        this.modalNextBtn?.addEventListener('click', async () => await this.nextStep());
        this.modalCreateBtn?.addEventListener('click', () => this.createKnowledgeBaseAgent());
        this.regenerateBtn?.addEventListener('click', () => this.generateDefinition());
        
        // ESC key handling
        this._escListener = (e) => {
            if (e.key === 'Escape') {
                // Only act if this modal is currently visible
                if (this.modal && this.modal.style.display !== 'none') {
                    e.stopPropagation();
                    e.preventDefault();
                    this.hide();
                }
            }
        };
        document.addEventListener('keydown', this._escListener, true);
        
        // Add agent name validation
        this.initAgentNameValidation();
        
        // Initialize CodeMirror for YAML syntax highlighting
        if (this.agentDefinitionTextarea && typeof CodeMirror !== 'undefined') {
            this.agentDefinitionCodeMirror = CodeMirror.fromTextArea(this.agentDefinitionTextarea, {
                mode: 'yaml',
                lineNumbers: true,
                lineWrapping: true,
                indentUnit: 2,
                tabSize: 2,
                theme: 'default'
            });
            
            // Update generated definition when CodeMirror changes
            this.agentDefinitionCodeMirror.on('change', () => {
                this.generatedDefinition = this.agentDefinitionCodeMirror.getValue();
            });
        } else {
            // Fallback for plain textarea
            this.agentDefinitionTextarea?.addEventListener('input', (e) => {
                this.generatedDefinition = e.target.value || '';
            });
        }
    }
    
    async loadKnowledgeBases() {
        console.log('📚 loadKnowledgeBases() function called');
        // Prefer modal-scoped container to avoid conflicts with the right-panel KB mode
        let knowledgeBaseList = document.getElementById('kbModalKnowledgeBaseList');
        if (!knowledgeBaseList) {
            knowledgeBaseList = document.getElementById('knowledgeBaseList');
        }
        if (!knowledgeBaseList) {
            console.error('❌ No knowledge base list container found (kbModalKnowledgeBaseList or knowledgeBaseList)');
            return;
        }

        console.log('✅ knowledge base list container found, showing loading state');
        
        // Get resource group from cached settings for immediate display
        const azureSettings = this.discoveryAgent.getCachedAzureSettings();
        const resourceGroup = azureSettings.resource_group;
        
        // Show loading state with resource group from the beginning
        const loadingMessage = resourceGroup 
            ? `Loading knowledge bases from ${resourceGroup}...`
            : 'Loading knowledge bases...';
            
        knowledgeBaseList.innerHTML = `
            <div class="loading-message" style="text-align: center; padding: 20px; color: #666;">
                <i class="fas fa-spinner fa-spin"></i> ${loadingMessage}
            </div>
        `;
        
        try {
            console.log('🌐 Fetching from /api/azure/knowledge-bases-v2');
            const response = await fetch('/api/azure/knowledge-bases-v2');
            console.log('📡 Response received:', response.status, response.statusText);
            const data = await response.json();
            console.log('📊 Response data:', data);
            
            if (data.success) {
                if (data.knowledgeBases && data.knowledgeBases.length > 0) {
                    // Clear loading message and populate knowledge bases
                        knowledgeBaseList.innerHTML = '';
                    // Preserve previously selected knowledge bases (if any)
                    const selectedSet = new Set((this.selectedKnowledgeBases || []).map(k => k.knowledgeBaseId));

                    // Sort knowledge bases: Succeeded status first, then alphabetically by name
                const sortedKBs = [...data.knowledgeBases].sort((a, b) => {
                    // First sort by status (Succeeded first)
                    const aSucceeded = a.provisioningState === 'Succeeded';
                    const bSucceeded = b.provisioningState === 'Succeeded';
                    
                    if (aSucceeded && !bSucceeded) return -1;
                    if (!aSucceeded && bSucceeded) return 1;
                    
                    // If same status, sort alphabetically by name
                    return a.name.localeCompare(b.name);
                });
                
                sortedKBs.forEach(kb => {
                    const kbItem = document.createElement('label');
                    const isSucceeded = kb.provisioningState === 'Succeeded';
                    
                    kbItem.className = isSucceeded ? 'knowledge-base-item' : 'knowledge-base-item disabled';
                    kbItem.innerHTML = `
                        <input type="checkbox" value="${kb.knowledgeBaseId}" data-name="${kb.name}" ${!isSucceeded ? 'disabled' : ''}>
                        <span class="checkmark"></span>
                        <div class="kb-info">
                            <div class="kb-name">${kb.name}</div>
                            <div class="kb-path">${kb.knowledgeBaseId}</div>
                            <div class="kb-bookshelf" style="font-size: 12px; color: #888;">Bookshelf: ${kb.bookshelfName}</div>
                            ${kb.provisioningState ? `<div class="kb-status" style="font-size: 12px; color: ${isSucceeded ? '#28a745' : '#dc3545'}; font-weight: ${isSucceeded ? '500' : '600'};">Status: ${kb.provisioningState}</div>` : ''}
                        </div>
                    `;
                    // Re-apply previous selection if this KB was previously selected
                    const checkboxEl = kbItem.querySelector('input[type="checkbox"]');
                    if (checkboxEl && selectedSet.has(kb.knowledgeBaseId) && !checkboxEl.disabled) {
                        checkboxEl.checked = true;
                    }
                    knowledgeBaseList.appendChild(kbItem);
                });
                
                console.log(`📚 Loaded ${data.knowledgeBases.length} knowledge bases dynamically (${sortedKBs.filter(kb => kb.provisioningState === 'Succeeded').length} available)`);
                // Re-initialize checkbox listeners and update selection/publish summary
                try {
                    this.initKnowledgeBaseSelection();
                    this.updatePublishSummary();
                } catch (e) {
                    console.warn('⚠️ Failed to re-init KB selection handlers in modal loader:', e);
                }
                } else {
                    // No knowledge bases found
                    const resourceGroupText = data.resourceGroup ? ` in resource group "${data.resourceGroup}"` : ' in the configured resource group';
                    knowledgeBaseList.innerHTML = `
                        <div class="no-knowledge-bases" style="text-align: center; padding: 20px; color: #666;">
                            <i class="fas fa-info-circle"></i> No knowledge bases found${resourceGroupText}.
                            <br><small style="color: #999;">Make sure bookshelves are deployed in the Azure resource group.</small>
                        </div>
                    `;
                }
            } else {
                throw new Error(data.error || 'Failed to load knowledge bases');
            }
        } catch (error) {
            console.error('❌ Error loading knowledge bases:', error);
            
            // Show error message
            knowledgeBaseList.innerHTML = `
                <div class="error-message" style="text-align: center; padding: 15px; color: #dc3545; background: #f8d7da; border: 1px solid #f5c6cb; border-radius: 4px;">
                    <i class="fas fa-exclamation-triangle"></i> Failed to load knowledge bases from Azure.
                    <br><small>${error.message}</small>
                    <br><small style="color: #999;">Check your Azure configuration in discovery_config.json</small>
                </div>
            `;
        }
    }
    
    show() {
        console.log('🔍 Knowledge Base Modal show() called');
        this.currentStep = 1;
        this.updateStepDisplay();
        this.modal.style.display = 'flex';
        this.agentNameInput?.focus();
        
        // Load knowledge bases dynamically when modal opens
        console.log('📚 About to call loadKnowledgeBases()');
        this.loadKnowledgeBases();
        
        // Trigger initial validation
        if (this.agentNameInput && this.agentNameInput.value) {
            this.agentNameInput.dispatchEvent(new Event('input'));
        }
    }

    // Global debugging function - can be called from browser console
    testLoadKnowledgeBases() {
        console.log('🧪 Test function called from console');
        this.loadKnowledgeBases();
    }
    
    hide() {
        this.modal.style.display = 'none';
        this.resetForm();
        
        // Clean up ESC listener
        if (this._escListener) {
            document.removeEventListener('keydown', this._escListener, true);
        }
    }
    
    resetForm() {
        this.agentNameInput.value = 'KnowledgeBaseAgent';
        this.domainsInput.value = '';
        
        // Reset CodeMirror or textarea
        if (this.agentDefinitionCodeMirror) {
            this.agentDefinitionCodeMirror.setValue('');
        } else {
            this.agentDefinitionTextarea.value = '';
        }
        
        this.generatedDefinition = '';
        this.currentStep = 1;
        this.updateStepDisplay();
    }
    
    async nextStep() {
        if (this.currentStep === 1) {
            // Validate form
            const name = this.agentNameInput.value.trim();
            if (!name) {
                this.showError('Please enter an agent name');
                return;
            }
            
            // Validate agent name
            const nameValidation = this.discoveryAgent.validateAgentName(name);
            if (!nameValidation.valid) {
                this.showError(`Agent name validation failed: ${nameValidation.error}`);
                // Focus on the name input field to help user fix the issue
                this.agentNameInput.focus();
                this.agentNameInput.style.borderColor = '#dc3545';
                return;
            }
            
            // Generate definition and wait for completion before moving to step 2
            await this.generateDefinition();
            this.currentStep = 2;
            this.updateStepDisplay();
        }
    }
    
    previousStep() {
        if (this.currentStep === 2) {
            this.currentStep = 1;
            this.updateStepDisplay();
        }
    }
    
    updateStepDisplay() {
        // Update footer step indicators
        this.footerStepIndicators.forEach((indicator, index) => {
            const stepNumber = index + 1;
            
            if (stepNumber === this.currentStep) {
                indicator.classList.add('active');
                indicator.style.background = '#0078d4';
                indicator.style.color = 'white';
            } else if (stepNumber < this.currentStep) {
                indicator.classList.remove('active');
                indicator.style.background = '#0078d4';
                indicator.style.color = 'white';
            } else {
                indicator.classList.remove('active');
                indicator.style.background = '#e5e5e5';
                indicator.style.color = '#666';
            }
        });
        
        // Update step content visibility
        this.step1.style.display = this.currentStep === 1 ? 'block' : 'none';
        this.step2.style.display = this.currentStep === 2 ? 'block' : 'none';
        
        // Update button visibility
        this.modalBackBtn.style.display = this.currentStep === 1 ? 'none' : 'inline-block';
        this.modalNextBtn.style.display = this.currentStep === 2 ? 'none' : 'inline-block';
        this.modalCreateBtn.style.display = this.currentStep === 2 ? 'inline-block' : 'none';
    }
    
    async generateDefinition() {
        const name = this.agentNameInput.value.trim();
        const domains = this.domainsInput.value.trim();
        
        if (!name) {
            this.showError('Please enter an agent name');
            return;
        }
        
        // Show loading state
        const originalText = this.regenerateBtn.textContent;
        this.regenerateBtn.disabled = true;
        this.regenerateBtn.innerHTML = '<div class="loading-spinner small"></div> Generating...';
        
        try {
            const response = await fetch('/api/generate-knowledge-base-agent', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: name,
                    domains: domains
                })
            });
            
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}: ${response.statusText}`);
            }
            
            const result = await response.json();
            
            if (result.success) {
                this.generatedDefinition = result.agent_definition;
                
                // Update CodeMirror or textarea
                if (this.agentDefinitionCodeMirror) {
                    this.agentDefinitionCodeMirror.setValue(this.generatedDefinition);
                } else {
                    this.agentDefinitionTextarea.value = this.generatedDefinition;
                }
            } else {
                throw new Error(result.error || 'Failed to generate agent definition');
            }
        } catch (error) {
            console.error('Error generating knowledge base agent definition:', error);
            this.showError(`Failed to generate agent definition: ${error.message}`);
        } finally {
            // Restore button state
            this.regenerateBtn.disabled = false;
            this.regenerateBtn.textContent = originalText;
        }
    }
    
    async createKnowledgeBaseAgent() {
        const name = this.agentNameInput.value.trim();
        
        // Get definition from CodeMirror or textarea
        const definition = this.agentDefinitionCodeMirror 
            ? this.agentDefinitionCodeMirror.getValue().trim()
            : this.agentDefinitionTextarea.value.trim();
        
        if (!name || !definition) {
            this.showError('Please ensure all fields are filled');
            return;
        }
        
        // Validate agent name
        const nameValidation = this.discoveryAgent.validateAgentName(name);
        if (!nameValidation.valid) {
            this.showError(`Agent name validation failed: ${nameValidation.error}`);
            // Focus on the name input field and switch back to step 1 to help user fix the issue
            this.currentStep = 1;
            this.updateStepDisplay();
            this.agentNameInput.focus();
            this.agentNameInput.style.borderColor = '#dc3545';
            return;
        }
        
        // Debug: log what we're sending
        console.log('Creating KB agent with:', { name, definitionLength: definition.length });
        
        // Show loading state
        const originalText = this.modalCreateBtn.textContent;
        this.modalCreateBtn.disabled = true;
        this.modalCreateBtn.innerHTML = '<div class="loading-spinner small"></div> Creating...';
        
        try {
            const response = await fetch('/api/create-knowledge-base-agent', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: name,
                    agent_definition: definition
                })
            });
            
            const result = await response.json();
            
            if (response.ok && result.success) {
                this.showSuccess(`Knowledge Base Agent '${name}' created successfully!`);
                this.hide();
                
                // Refresh available agents
                await this.discoveryAgent.loadAvailableAgents();
                this.discoveryAgent.renderAgentDropdown();
                
                // Automatically select the new Knowledge Base agent
                if (result.agentName) {
                    // Search for the new agent in kb_agents
                    let newAgent = null;
                    if (this.discoveryAgent.availableAgents.kb_agents) {
                        newAgent = this.discoveryAgent.availableAgents.kb_agents.find(a => a.name === result.agentName);
                    }
                    if (newAgent) {
                        await this.discoveryAgent.selectAgent(newAgent);
                        // Ensure right panel enters KB Agent mode
                        this.discoveryAgent.handleAgentModeSwitch(newAgent);
                    }
                }
            } else {
                // Check if the error is about agent already existing
                if (result.error && result.error.includes('already exists')) {
                    this.showOverwriteConfirmation(result.error);
                } else {
                    throw new Error(result.error || 'Failed to create agent');
                }
            }
        } catch (error) {
            console.error('Error creating knowledge base agent:', error);
            this.showError(`Failed to create agent: ${error.message}`);
        } finally {
            // Restore button state
            this.modalCreateBtn.disabled = false;
            this.modalCreateBtn.textContent = originalText;
        }
    }
    
    async showOverwriteConfirmation(errorMessage) {
        // Extract agent name from error message
        const agentNameMatch = errorMessage.match(/Knowledge Base Agent "([^"]+)" already exists/);
        const agentName = agentNameMatch ? agentNameMatch[1] : 'this agent';
        
        const shouldOverwrite = await showAppDialog({
            title: 'Overwrite existing Knowledge Base agent',
            message: `${errorMessage}\n\nDo you want to overwrite the existing Knowledge Base agent "${agentName}"?`,
            okLabel: 'Overwrite',
            cancelLabel: 'Cancel'
        });
        
        if (shouldOverwrite) {
            // Re-create the agent with overwrite flag
            this.createKnowledgeBaseAgentWithOverwrite();
        }
        // If they click Cancel, the dialog remains open and they can modify the name
    }
    
    async createKnowledgeBaseAgentWithOverwrite() {
        const name = this.agentNameInput.value.trim();
        
        // Get definition from CodeMirror or textarea
        const definition = this.agentDefinitionCodeMirror 
            ? this.agentDefinitionCodeMirror.getValue().trim()
            : this.agentDefinitionTextarea.value.trim();
        
        if (!name || !definition) {
            this.showError('Please ensure all fields are filled');
            return;
        }
        
        // Validate agent name
        const nameValidation = this.discoveryAgent.validateAgentName(name);
        if (!nameValidation.valid) {
            this.showError(`Agent name validation failed: ${nameValidation.error}`);
            // Focus on the name input field and switch back to step 1 to help user fix the issue
            this.currentStep = 1;
            this.updateStepDisplay();
            this.agentNameInput.focus();
            this.agentNameInput.style.borderColor = '#dc3545';
            return;
        }
        
        // Debug: log what we're sending
        console.log('Overwriting KB agent with:', { name, definitionLength: definition.length });
        
        // Show loading state
        const originalText = this.modalCreateBtn.textContent;
        this.modalCreateBtn.disabled = true;
        this.modalCreateBtn.innerHTML = '<div class="loading-spinner small"></div> Overwriting...';
        
        try {
            const response = await fetch('/api/create-knowledge-base-agent', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: name,
                    agent_definition: definition,
                    overwrite: true
                })
            });
            
            const result = await response.json();
            
            if (response.ok && result.success) {
                this.showSuccess(`Knowledge Base Agent '${name}' overwritten successfully!`);
                this.hide();
                
                // Refresh available agents
                await this.discoveryAgent.loadAvailableAgents();
                this.discoveryAgent.renderAgentDropdown();
                
                // Automatically select the overwritten Knowledge Base agent
                if (result.agentName) {
                    // Search for the agent in kb_agents
                    let newAgent = null;
                    if (this.discoveryAgent.availableAgents.kb_agents) {
                        newAgent = this.discoveryAgent.availableAgents.kb_agents.find(a => a.name === result.agentName);
                    }
                    if (newAgent) {
                        await this.discoveryAgent.selectAgent(newAgent);
                        // Ensure right panel enters KB Agent mode
                        this.discoveryAgent.handleAgentModeSwitch(newAgent);
                    }
                }
            } else {
                this.showError('Failed to overwrite agent: ' + result.error);
            }
        } catch (error) {
            console.error('Error overwriting knowledge base agent:', error);
            this.showError(`Failed to overwrite agent: ${error.message}`);
        } finally {
            // Restore button state
            this.modalCreateBtn.disabled = false;
            this.modalCreateBtn.textContent = originalText;
        }
    }
    
    showError(message) {
        // Reuse the existing error display mechanism
        if (this.discoveryAgent.showError) {
            this.discoveryAgent.showError(message);
        } else {
            alert(message);
        }
    }
    
    showSuccess(message) {
        // Reuse the existing success display mechanism  
        if (this.discoveryAgent.showToast) {
            this.discoveryAgent.showToast(message, 'success');
        } else {
            alert(message);
        }
    }
    
    initAgentNameValidation() {
        const nameInput = this.agentNameInput;
        // KB agent name validation element removed from right-panel; guard access.
        const validationDiv = document.getElementById('kbAgentNameValidation');
        // If validationDiv is missing, skip name validation logic silently.
        if (!validationDiv) {
            return;
        }
        
        if (nameInput && validationDiv) {
            // Real-time validation
            const validateName = () => {
                const name = nameInput.value.trim();
                const validation = this.discoveryAgent.validateAgentName(name);
                
                validationDiv.style.display = 'block';
                if (validation.valid) {
                    validationDiv.textContent = '✅ Valid agent name';
                    validationDiv.style.color = '#28a745';
                    nameInput.style.borderColor = '#28a745';
                } else {
                    validationDiv.textContent = `❌ ${validation.error}`;
                    validationDiv.style.color = '#dc3545';
                    nameInput.style.borderColor = '#dc3545';
                }
                
                // Enable/disable Next button based on validation
                const nextBtn = this.modalNextBtn;
                if (nextBtn && this.currentStep === 1) {
                    nextBtn.disabled = !validation.valid;
                }
            };
            
            // Bind validation events
            nameInput.addEventListener('input', validateName);
            nameInput.addEventListener('blur', validateName);
            
            // Initial validation
            if (nameInput.value) {
                validateName();
            }
        }
    }
}

// Select Agent Dialog Class (formerly LoadAgentDialog)
class SelectAgentDialog {
    constructor(discoveryAgent) {
        this.discoveryAgent = discoveryAgent;
        this.currentStep = 1;
        this.selectedAgentType = 'tool';
        
        this.initializeElements();
        this.bindEvents();
    }

    initializeElements() {
    // Modal elements
    this.modal = document.getElementById('selectAgentDialog');
    this.closeBtn = document.getElementById('selectAgentModalCloseBtn');
    this.cancelBtn = document.getElementById('selectAgentCancelBtn');
    this.backBtn = document.getElementById('selectAgentBackBtn');
    this.nextBtn = document.getElementById('selectAgentNextBtn');
    this.loadBtn = document.getElementById('selectAgentLoadBtn');
        
        // Step elements
    this.step1 = document.getElementById('selectAgentStep1');
    this.step2 = document.getElementById('selectAgentStep2');
    this.step2Title = document.getElementById('selectAgentStep2Title');
    this.step2Description = document.getElementById('selectAgentStep2Description');
        
        // Agent type radio buttons
        this.agentTypeRadios = document.querySelectorAll('input[name="agentType"]');
        
        // Agent field containers
        this.toolAgentFields = document.getElementById('toolAgentFields');
        this.workflowAgentFields = document.getElementById('workflowAgentFields');
        this.kbAgentFields = document.getElementById('kbAgentFields');
        
        // Step indicators
        this.stepIndicators = this.modal.querySelectorAll('.step-indicator');
    }

    bindEvents() {
        // Close modal events
        this.closeBtn?.addEventListener('click', () => this.close());
        this.cancelBtn?.addEventListener('click', () => this.close());
        
        // Step navigation events
        this.backBtn?.addEventListener('click', () => this.previousStep());
        this.nextBtn?.addEventListener('click', () => this.nextStep());
        this.loadBtn?.addEventListener('click', () => this.loadAgent());
        
        // Agent type selection events
        this.agentTypeRadios.forEach(radio => {
            radio.addEventListener('change', () => {
                this.onAgentTypeChange(radio.value);
                // If in selector-only mode, treat selection as immediate choice
                if (this._selectorMode) {
                    this._handleSelectorChoice(radio.value);
                }
            });
        });
        
        // Make entire radio option clickable
        const radioOptions = this.modal.querySelectorAll('.radio-option');
        radioOptions.forEach(option => {
            option.addEventListener('click', (e) => {
                // Don't trigger if clicked directly on radio input or label
                if (e.target.type === 'radio' || e.target.tagName === 'LABEL') return;
                
                const radio = option.querySelector('input[type="radio"]');
                if (radio) {
                    radio.checked = true;
                    radio.dispatchEvent(new Event('change'));
                }
            });
        });
        
        // Modal backdrop click to close
        this.modal?.addEventListener('click', (e) => {
            if (e.target === this.modal) {
                this.close();
            }
        });
        
        // Add input event listeners for real-time validation
        this.setupRealTimeValidation();
    }

    setupRealTimeValidation() {
        // Get all form inputs in the Load Agent dialog
        const allInputs = this.modal.querySelectorAll('input[type="text"], textarea');
        
        allInputs.forEach(input => {
            // Listen for both input and change events to catch all value updates
            input.addEventListener('input', () => {
                this.updateLoadButtonState();
            });
            input.addEventListener('change', () => {
                this.updateLoadButtonState();
            });
        });
    }

    updateLoadButtonState() {
        if (this.currentStep === 2 && this.loadBtn) {
            const isValid = this.validateCurrentForm();
            this.loadBtn.disabled = !isValid;
            
            if (isValid) {
                this.loadBtn.classList.remove('btn-disabled');
            } else {
                this.loadBtn.classList.add('btn-disabled');
            }
        }
    }

    show() {
        this.currentStep = 1;
        this.updateStepDisplay();
        this.resetForm();
        
        // Update placeholders with current configuration
        if (this.discoveryAgent && typeof this.discoveryAgent.updatePlaceholders === 'function') {
            this.discoveryAgent.updatePlaceholders();
        }
        // Ensure the modal title is correct for load mode
        const titleEl = document.getElementById('selectAgentModalTitle');
        if (titleEl) titleEl.textContent = 'Load Agent';

        if (this.modal) {
            this.modal.classList.remove('hidden');
        }
    }

    // Show the dialog as a selector-only (hide footer and make radio clicks close dialog
    showSelectorMode() {
        this._selectorMode = true;
        // hide footer actions to make it a selector-only dialog
        try {
            const footer = this.modal.querySelector('.modal-footer');
            if (footer) footer.classList.add('hidden');
        } catch (e) { /* ignore */ }
        // Always show step 1 only
        this.currentStep = 1;
        this.updateStepDisplay();
        // Make sure radios are visible and reset form
        this.resetForm();
        // Set modal title to 'Create Agent' when in selector mode
        const titleEl = document.getElementById('selectAgentModalTitle');
        if (titleEl) titleEl.textContent = 'Create Agent';

        if (this.modal) this.modal.classList.remove('hidden');
    }

    // Restore normal dialog behavior
    hideSelectorMode() {
        this._selectorMode = false;
        try {
            const footer = this.modal.querySelector('.modal-footer');
            if (footer) footer.classList.remove('hidden');
        } catch (e) {}
    }

    _handleSelectorChoice(choice) {
        try {
            // Close the dialog
            this.close();
        } catch (e) {}

        // Restore selector mode state for next time
        this.hideSelectorMode();

        // Invoke the appropriate wizard on the discoveryAgent
        if (!this.discoveryAgent) return;
        if (choice === 'tool') {
            if (typeof this.discoveryAgent.showCreateToolAgentModal === 'function') {
                this.discoveryAgent.showCreateToolAgentModal();
            }
        } else if (choice === 'entry') {
            if (typeof this.discoveryAgent.showCreateAgentModal === 'function') {
                this.discoveryAgent.showCreateAgentModal();
            }
        } else if (choice === 'kb') {
            if (typeof this.discoveryAgent.showCreateKnowledgeBaseModal === 'function') {
                this.discoveryAgent.showCreateKnowledgeBaseModal();
            }
        }
    }

    close() {
        if (this.modal) {
            this.modal.classList.add('hidden');
        }
    }

    resetForm() {
        // Reset to first step
        this.currentStep = 1;
        
        // Reset agent type selection
        const toolRadio = document.getElementById('agentTypeTool');
        if (toolRadio) {
            toolRadio.checked = true;
            this.selectedAgentType = 'tool';
        }
        
        // Clear all form fields
        const allInputs = this.modal.querySelectorAll('input[type="text"], textarea');
        allInputs.forEach(input => {
            input.value = '';
        });
        
        // Update agent type display
        this.onAgentTypeChange('tool');
        this.updateStepDisplay();
    }

    onAgentTypeChange(agentType) {
        this.selectedAgentType = agentType;
        
        // Hide all field containers
        this.toolAgentFields?.classList.add('hidden');
        this.workflowAgentFields?.classList.add('hidden');
        this.kbAgentFields?.classList.add('hidden');
        
        // Show appropriate field container and update step 2 title
        switch (agentType) {
            case 'tool':
                this.toolAgentFields?.classList.remove('hidden');
                if (this.step2Title) this.step2Title.textContent = 'Configure Tool Agent Files';
                if (this.step2Description) this.step2Description.textContent = 'Provide the relative paths to the tool agent configuration files';
                break;
            case 'entry':
                this.workflowAgentFields?.classList.remove('hidden');
                if (this.step2Title) this.step2Title.textContent = 'Configure Workflow Agent Files';
                if (this.step2Description) this.step2Description.textContent = 'Provide the workflow agent details and configuration file path';
                break;
            case 'kb':
                this.kbAgentFields?.classList.remove('hidden');
                if (this.step2Title) this.step2Title.textContent = 'Configure Knowledge Base Agent Files';
                if (this.step2Description) this.step2Description.textContent = 'Provide the KB agent configuration file path';
                break;
        }
        
        // Update load button state when agent type changes
        this.updateLoadButtonState();
    }

    nextStep() {
        if (this.currentStep === 1) {
            this.currentStep = 2;
            this.updateStepDisplay();
        }
    }

    previousStep() {
        if (this.currentStep === 2) {
            this.currentStep = 1;
            this.updateStepDisplay();
        }
    }

    updateStepDisplay() {
        // Hide all steps
        this.step1?.classList.remove('active');
        this.step2?.classList.remove('active');
        
        // Show current step
        if (this.currentStep === 1) {
            this.step1?.classList.add('active');
            this.backBtn?.classList.add('hidden');
            this.nextBtn?.classList.remove('hidden');
            this.loadBtn?.classList.add('hidden');
        } else if (this.currentStep === 2) {
            this.step2?.classList.add('active');
            this.backBtn?.classList.remove('hidden');
            this.nextBtn?.classList.add('hidden');
            this.loadBtn?.classList.remove('hidden');
            
            // Update load button state when showing step 2
            this.updateLoadButtonState();
        }
        
        // Update step indicators
        this.stepIndicators.forEach((indicator, index) => {
            const stepNumber = index + 1;
            if (stepNumber <= this.currentStep) {
                indicator.classList.add('active');
            } else {
                indicator.classList.remove('active');
            }
        });
    }

    validateForm() {
        return this.validateCurrentForm();
    }

    validateCurrentForm() {
        const getFieldValue = (id) => {
            const field = document.getElementById(id);
            return field ? field.value.trim() : '';
        };

        const validateRequired = (fields) => {
            const missingFields = [];
            const result = fields.every(fieldId => {
                const value = getFieldValue(fieldId);
                if (value === '') {
                    missingFields.push(fieldId);
                    return false;
                }
                return true;
            });
            
            // Debug logging
            if (!result) {
                console.log('Validation failed for fields:', missingFields);
                fields.forEach(fieldId => {
                    console.log(`Field ${fieldId}:`, getFieldValue(fieldId));
                });
            }
            
            return result;
        };

        switch (this.selectedAgentType) {
            case 'tool':
                return validateRequired(['loadToolAgentConfig', 'loadToolDefinition', 'loadToolDockerfile']);
            case 'entry':
                return validateRequired(['loadWorkflowAgentConfig']);
            case 'kb':
                return validateRequired(['loadKbAgentConfig']);
            default:
                return false;
        }
    }

    async loadAgent() {
        if (!this.validateForm()) {
            await showAppAlert({
                title: 'Validation Error',
                message: 'Please fill in all required fields before loading the agent.'
            });
            return;
        }

        try {
            const agentData = this.collectFormData();
            
            // Show loading state
            this.loadBtn.disabled = true;
            this.loadBtn.textContent = 'Loading...';
            
            const response = await fetch('/api/load-agent', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(agentData)
            });

            const result = await response.json();

            if (response.ok && result.success) {
                console.log('✅ Agent loaded successfully, response:', result);
                
                // Reload agents list and switch to the new agent directly
                await this.discoveryAgent.loadAvailableAgents();
                this.discoveryAgent.renderAgentDropdown();
                
                // Use the agent name from the server response instead of form data
                const agentName = result.agentName;
                console.log('🔍 Looking for agent with name:', agentName);
                
                if (agentName) {
                    const loadedAgent = this.findAgentByName(agentName);
                    console.log('🔍 Found agent:', loadedAgent);
                    
                    if (loadedAgent) {
                        console.log('🔄 Switching to loaded agent...');
                        await this.discoveryAgent.selectAgent(loadedAgent);
                    } else {
                        console.warn(`Could not find loaded agent: ${agentName}`);
                    }
                } else {
                    console.warn('No agent name returned from server');
                }
                
                this.close();
            } else {
                throw new Error(result.error || 'Failed to load agent');
            }
        } catch (error) {
            console.error('Error loading agent:', error);
            await showAppAlert({
                title: 'Load Error',
                message: `Failed to load agent: ${error.message}`
            });
        } finally {
            // Reset button state
            this.loadBtn.disabled = false;
            this.loadBtn.textContent = 'Load';
        }
    }

    collectFormData() {
        const getFieldValue = (id) => {
            const field = document.getElementById(id);
            return field ? field.value.trim() : '';
        };

        const baseData = {
            agentType: this.selectedAgentType
        };

        switch (this.selectedAgentType) {
            case 'tool':
                return {
                    ...baseData,
                    agentConfig: getFieldValue('loadToolAgentConfig'),
                    toolsDefinition: getFieldValue('loadToolDefinition'),
                    dockerfile: getFieldValue('loadToolDockerfile'),
                    envVars: getFieldValue('loadToolEnvVars') || null
                };
            case 'entry':
                return {
                    ...baseData,
                    agentConfig: getFieldValue('loadWorkflowAgentConfig')
                };
            case 'kb':
                return {
                    ...baseData,
                    agentConfig: getFieldValue('loadKbAgentConfig')
                };
            default:
                return baseData;
        }
    }

    // File browser functionality
    browseForFile(inputId) {
        // Create a hidden file input element
        const fileInput = document.createElement('input');
        fileInput.type = 'file';
        fileInput.style.display = 'none';
        
        // Set appropriate file filters based on the input field
        if (inputId.includes('Dockerfile') || inputId.includes('dockerfile')) {
            fileInput.accept = '*'; // Dockerfiles don't have extensions
        } else if (inputId.includes('Config') || inputId.includes('Definition')) {
            fileInput.accept = '.yaml,.yml,.json';
        } else {
            fileInput.accept = '*'; // Accept all files as fallback
        }
        
        // Handle file selection
        fileInput.addEventListener('change', (event) => {
            const file = event.target.files[0];
            if (file) {
                // Since HTML5 file API doesn't provide full paths for security reasons,
                // we'll use the file name and try to resolve it via the backend
                this.resolveFilePath(file.name, inputId);
            }
            
            // Clean up the file input
            document.body.removeChild(fileInput);
        });
        
        // Add to DOM and trigger click
        document.body.appendChild(fileInput);
        fileInput.click();
    }
    
    // Helper method to get the agent config input field based on current agent type
    getAgentConfigInput() {
        switch (this.selectedAgentType) {
            case 'tool':
                return document.getElementById('loadToolAgentConfig');
            case 'entry':
                return document.getElementById('loadWorkflowAgentConfig');
            case 'kb':
                return document.getElementById('loadKbAgentConfig');
            default:
                return null;
        }
    }
    
    async resolveFilePath(fileName, inputId) {
        try {
            // Get context from agent config file if available
            let contextPath = '';
            const agentConfigInput = this.getAgentConfigInput();
            if (agentConfigInput && agentConfigInput.value.trim()) {
                contextPath = agentConfigInput.value.trim();
                console.log(`🔍 Using context path for ${fileName}: ${contextPath}`);
            } else {
                console.log(`🔍 No context available for ${fileName}, using global search`);
            }
            
            // Call backend to find possible file paths
            const response = await fetch('/api/resolve-file-path', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ 
                    fileName,
                    contextPath: contextPath
                })
            });
            
            if (response.ok) {
                const result = await response.json();
                if (result.paths && result.paths.length > 0) {
                    // Use the first found path, or show options if multiple
                    const targetInput = document.getElementById(inputId);
                    if (targetInput) {
                        if (result.paths.length === 1) {
                            targetInput.value = result.paths[0];
                            // Trigger validation after setting the value
                            this.updateLoadButtonState();
                        } else {
                            // Multiple paths found - show selection
                            await this.showPathSelectionDialog(result.paths, inputId);
                        }
                    }
                } else {
                    // No paths found from file search, try smart default path generation
                    const targetInput = document.getElementById(inputId);
                    if (targetInput) {
                        try {
                            targetInput.value = await this.generateSmartDefaultPath(fileName, inputId);
                            // Trigger validation after setting the value
                            this.updateLoadButtonState();
                        } catch (error) {
                            // Smart path generation failed
                            targetInput.value = '';
                            console.error(`Failed to generate smart path for ${fileName}:`, error.message);
                            
                            // Show user-friendly error
                            this.showError(`Could not resolve path for ${fileName}: ${error.message}`);
                            
                            // Trigger validation to show the error state
                            this.updateLoadButtonState();
                        }
                    }
                }
            }
        } catch (error) {
            console.error('Error resolving file path:', error);
            // Try smart path generation as fallback
            const targetInput = document.getElementById(inputId);
            if (targetInput) {
                try {
                    targetInput.value = await this.generateSmartDefaultPath(fileName, inputId);
                    // Trigger validation after setting the value
                    this.updateLoadButtonState();
                } catch (smartPathError) {
                    // Both resolution and smart path generation failed
                    targetInput.value = '';
                    
                    // Show user-friendly error
                    this.showError(`Path resolution failed for ${fileName}: ${smartPathError.message}`);
                    
                    // Trigger validation to show the error state
                    this.updateLoadButtonState();
                }
            }
        }
    }
    
    async generateSmartDefaultPath(fileName, inputId) {
        const lowerFileName = fileName.toLowerCase();
        const lowerInputId = inputId.toLowerCase();
        
        // Get directory configuration from backend
        let toolAgentsDir = null;
        try {
            const response = await fetch('/api/config/directories');
            console.log('🔧 Directory config response status:', response.status);
            if (response.ok) {
                const data = await response.json();
                console.log('🔧 Directory config data:', data);
                if (data.status === 'success') {
                    toolAgentsDir = data.directories.tool_agents_dir;
                    console.log('🔧 Found tool_agents_dir:', toolAgentsDir);
                } else {
                    console.warn('🔧 Directory config request failed:', data.message);
                }
            } else {
                console.warn('🔧 Directory config HTTP error:', response.status, response.statusText);
            }
        } catch (error) {
            console.warn('Could not fetch directory config:', error);
        }
        
        // If we can't get the configuration, fail with a clear error
        if (!toolAgentsDir) {
            throw new Error('Tool agents directory not configured. Please check your discovery configuration.');
        }
        
        // Try to extract agent folder name from existing agent config input
        let agentFolderName = null;
        const agentConfigInput = this.getAgentConfigInput();
        if (agentConfigInput && agentConfigInput.value.trim()) {
            const configPath = agentConfigInput.value.trim();
            // Extract folder name from path like "../../sample-tools-and-models/ToolAgents/SomeAgent/agent.yaml"
            const pathParts = configPath.split('/');
            // Find the part that comes after "ToolAgents", "EntryAgents", or "KBAgents"
            for (let i = 0; i < pathParts.length - 1; i++) {
                if (pathParts[i] === 'ToolAgents' || pathParts[i] === 'WorkflowAgents' || pathParts[i] === 'KBAgents') {
                    if (i + 1 < pathParts.length) {
                        agentFolderName = pathParts[i + 1];
                        break;
                    }
                }
            }
        }
        
        // If we can't extract agent folder name from context, try to derive it from filename
        // Use a more flexible approach that doesn't enforce strict naming conventions
        if (!agentFolderName) {
            // Try to extract agent name from filename patterns
            const baseFileName = fileName.replace(/\.(yaml|yml|json)$/i, '');
            
            // Try common patterns for agent files
            if (baseFileName.toLowerCase().endsWith('-agent')) {
                agentFolderName = baseFileName.slice(0, -6); // Remove "-agent" suffix
            } else if (baseFileName.toLowerCase().endsWith('agent')) {
                agentFolderName = baseFileName.slice(0, -5); // Remove "agent" suffix
            } else if (baseFileName.toLowerCase().endsWith('-agent-definition')) {
                agentFolderName = baseFileName.slice(0, -17); // Remove "-agent-definition" suffix
            } else if (baseFileName.toLowerCase().endsWith('-tool-definition')) {
                agentFolderName = baseFileName.slice(0, -16); // Remove "-tool-definition" suffix
            } else if (baseFileName.toLowerCase().endsWith('-tool')) {
                agentFolderName = baseFileName.slice(0, -5); // Remove "-tool" suffix
            } else {
                // Use the base filename as the agent folder name for any other file
                agentFolderName = baseFileName;
            }
            console.log(`🔧 Derived agent folder name from filename: ${agentFolderName}`);
        }
        
        // If we still can't determine agent folder name, use a fallback
        if (!agentFolderName) {
            // Use the base filename without extension as fallback
            agentFolderName = fileName.replace(/\.(yaml|yml|json)$/i, '');
            console.log(`🔧 Using fallback agent folder name: ${agentFolderName}`);
        }
        
        // Smart path generation based on file type and input context
        if (lowerFileName.includes('dockerfile') || lowerInputId.includes('dockerfile')) {
            return `${toolAgentsDir}${agentFolderName}/${fileName}`;
        } else if (lowerInputId.includes('definition') || lowerFileName.includes('definition')) {
            return `${toolAgentsDir}${agentFolderName}/${fileName}`;
        } else if (lowerInputId.includes('config') || lowerInputId.includes('agent')) {
            return `${toolAgentsDir}${agentFolderName}/${fileName}`;
        } else {
            // For unknown file types, still use the config-driven path
            return `${toolAgentsDir}${agentFolderName}/${fileName}`;
        }
    }
    
    async showPathSelectionDialog(paths, inputId) {
        const pathOptions = paths.map(path => `<option value="${path}">${path}</option>`).join('');
        
        const dialogHtml = `
            <div class="path-selection-dialog">
                <h4>Multiple files found with this name:</h4>
                <select id="pathSelector" class="form-control">
                    ${pathOptions}
                </select>
                <div class="mt-3">
                    <button onclick="discoveryAgent.selectAgentDialog.selectPath('${inputId}')" class="btn btn-primary">Select</button>
                    <button onclick="discoveryAgent.selectAgentDialog.cancelPathSelection()" class="btn btn-secondary">Cancel</button>
                </div>
            </div>
        `;
        
        // For simplicity, just use the first path for now
        // In a full implementation, you'd show a proper modal dialog
        const targetInput = document.getElementById(inputId);
        if (targetInput) {
            targetInput.value = paths[0];
            // Trigger validation after setting the value
            this.updateLoadButtonState();
        }
    }
    
    findAgentByName(name) {
        console.log('🔍 findAgentByName called with:', name);
        console.log('🔍 Available agents structure:', this.discoveryAgent.availableAgents);
        
        // Search through all available agent categories
        const agentLists = [
            this.discoveryAgent.availableAgents?.tool_agents || [],
            this.discoveryAgent.availableAgents?.workflow_agents || [],
            this.discoveryAgent.availableAgents?.kb_agents || [],
            this.discoveryAgent.availableAgents?.tool_agents || []
        ];
        
        for (let i = 0; i < agentLists.length; i++) {
            const agentList = agentLists[i];
            console.log(`🔍 Searching in list ${i}:`, agentList);
            
            const found = agentList.find(agent => {
                console.log(`🔍 Comparing '${agent.name}' with '${name}'`);
                return agent.name === name;
            });
            
            if (found) {
                console.log('✅ Found agent:', found);
                return found;
            }
        }
        
        console.log('❌ Agent not found');
        return null;
    }
    
    convertToRelativePath(fileName, webkitPath) {
        // Legacy method - keeping for compatibility
        if (webkitPath) {
            return './' + webkitPath;
        }
        
        const lowerFileName = fileName.toLowerCase();
        
        if (lowerFileName.includes('dockerfile')) {
            return './docker/' + fileName;
        } else if (lowerFileName.includes('tool') && (lowerFileName.endsWith('.yaml') || lowerFileName.endsWith('.yml'))) {
            if (lowerFileName.includes('definition')) {
                return './tools/' + fileName;
            } else {
                return './agents/' + fileName;
            }
        } else if (lowerFileName.endsWith('.yaml') || lowerFileName.endsWith('.yml') || lowerFileName.endsWith('.json')) {
            return './agents/' + fileName;
        } else {
            return './' + fileName;
        }
    }
    
    showError(message) {
        // Delegate to the discovery agent's showError method
        if (this.discoveryAgent && this.discoveryAgent.showError) {
            this.discoveryAgent.showError(message);
        } else {
            // Fallback to console error and alert
            console.error('SelectAgentDialog Error:', message);
            alert('Error: ' + message);
        }
    }
}

// Global debugging methods for SKU cache management
window.debugSKUCache = function() {
    if (window.discoveryAgent) {
        const cacheInfo = window.discoveryAgent.getVMSkuCacheInfo();
        console.log('🔍 VM SKU Cache Information:', cacheInfo);
        
        console.log('\n📊 Cache Summary:');
        console.log(`  - In-memory SKUs: ${cacheInfo.inMemorySkuCount}`);
        console.log(`  - LocalStorage entries: ${cacheInfo.localStorageEntries.length}`);
        
        if (cacheInfo.localStorageEntries.length > 0) {
            console.log('\n💾 LocalStorage Cache Entries:');
            cacheInfo.localStorageEntries.forEach((entry, index) => {
                if (entry.error) {
                    console.log(`  ${index + 1}. ${entry.key} - ERROR: ${entry.error}`);
                } else {
                    console.log(`  ${index + 1}. ${entry.key}`);
                    console.log(`     SKUs: ${entry.skuCount}, Created: ${entry.timestamp}`);
                    console.log(`     Expires: ${entry.expiry}, Expired: ${entry.expired ? '❌' : '✅'}`);
                }
            });
        }
        
        return cacheInfo;
    } else {
        console.warn('❌ DiscoveryAgent not available');
        return null;
    }
};

window.clearSKUCache = function() {
    if (window.discoveryAgent) {
        window.discoveryAgent.clearVMSkuCache();
        console.log('✅ VM SKU cache cleared');
    } else {
        console.warn('❌ DiscoveryAgent not available');
    }
};

window.loadSKUs = async function(forceRefresh = false) {
    if (window.discoveryAgent) {
        console.log(`🔄 Loading VM SKUs (force refresh: ${forceRefresh})`);
        await window.discoveryAgent.loadVMSkus(forceRefresh);
        console.log(`✅ VM SKUs loaded: ${window.discoveryAgent.vmSkus?.length || 0} SKUs`);
        return window.discoveryAgent.vmSkus;
    } else {
        console.warn('❌ DiscoveryAgent not available');
        return null;
    }
};
